+void VoxelLayer::onInitialize()
+{
+  ObstacleLayer::onInitialize();
+  ros::NodeHandle private_nh("~/" + name_);
+  
+  std::string costmap_name_ = name_.substr(0, name_.find("/"));
+  ros::NodeHandle pnh("~/" + costmap_name_);
+
+  private_nh.param("publish_voxel_map", publish_voxel_, false);
+  pnh.param("robot_frame", robot_base_frame_, std::string("base_link"));
+
+  if (publish_voxel_)
+    voxel_pub_ = private_nh.advertise <VoxelGrid > ("voxel_grid", 1);
+
+  clearing_endpoints_pub_ = private_nh.advertise<sensor_msgs::PointCloud>("clearing_endpoints", 1);
+}
+
+void VoxelLayer::setupDynamicReconfigure(ros::NodeHandle& nh)
+{
+  voxel_dsrv_ = new dynamic_reconfigure::Server<VoxelPluginConfig>(nh);
+  dynamic_reconfigure::Server<VoxelPluginConfig>::CallbackType cb = boost::bind(
+      &VoxelLayer::reconfigureCB, this, _1, _2);
+  voxel_dsrv_->setCallback(cb);
+}
+
+VoxelLayer::~VoxelLayer()
+{
+  if (voxel_dsrv_)
+    delete voxel_dsrv_;
+}
+
+void VoxelLayer::reconfigureCB(VoxelPluginConfig &config, uint32_t level)
+{
+  enabled_ = config.enabled;
+  footprint_clearing_enabled_ = config.footprint_clearing_enabled;
+  max_obstacle_height_ = config.max_obstacle_height;
+  size_z_ = config.z_voxels;
+  origin_z_ = config.origin_z;
+  z_resolution_ = config.z_resolution;
+  unknown_threshold_ = config.unknown_threshold + (VOXEL_BITS - size_z_);
+  mark_threshold_ = config.mark_threshold;
+  combination_method_ = config.combination_method;
+  matchSize();
+}
+
+void VoxelLayer::matchSize()
+{
+  ObstacleLayer::matchSize();
+  voxel_grid_.resize(size_x_, size_y_, size_z_);
+ // ROS_ASSERT(voxel_grid_.sizeX() == size_x_ && voxel_grid_.sizeY() == size_y_ && voxel_grid_.sizeZ() == size_z_);
+}
+
+void VoxelLayer::reset()
+{
+  deactivate();
+  resetMaps();
+  voxel_grid_.reset();
+  activate();
+}
+
+void VoxelLayer::resetMaps()
+{
+  Costmap2D::resetMaps();
+  voxel_grid_.reset();
+}
+
+void VoxelLayer::updateBounds(double robot_x, double robot_y, double robot_yaw, double* min_x,
+                                       double* min_y, double* max_x, double* max_y)
+{
+  if (rolling_window_) {
+      updateOrigin(robot_x - getSizeInMetersX() / 2, robot_y - getSizeInMetersY() / 2 );
+  }
+
+  if (!enabled_)
+    return;
+
+  useExtraBounds(min_x, min_y, max_x, max_y);
+
+  bool current = true;
+  std::vector<Observation> observations, clearing_observations;
+
+  // get the marking observations
+  current = getMarkingObservations(observations) && current;
+
+  // get the clearing observations
+  current = getClearingObservations(clearing_observations) && current;
+
+  // update the global current status
+  current_ = current;
+
+  // raytrace freespace
+  for (unsigned int i = 0; i < clearing_observations.size(); ++i)
+  {
+    raytraceFreespace(clearing_observations[i], min_x, min_y, max_x, max_y);
+  }
+
+  // place the new obstacles into a priority queue... each with a priority of zero to begin with
+  for (std::vector<Observation>::const_iterator it = observations.begin(); it != observations.end(); ++it)
+  {
+    const Observation& obs = *it;
+
+#ifdef COSTMAP_2D_POINTCLOUD2
+    const sensor_msgs::PointCloud2& cloud = *(obs.cloud_);
+    // Note that these points are already filtered with max and min obstacle heights
+    // You will have to adjust param file to see points beyond default settings
+    sensor_msgs::PointCloud2ConstIterator<float> iter_x(cloud, "x");
+    sensor_msgs::PointCloud2ConstIterator<float> iter_y(cloud, "y");
+    sensor_msgs::PointCloud2ConstIterator<float> iter_z(cloud, "z");
+
+    for (unsigned int i = 0; iter_x != iter_x.end(); ++iter_x, ++iter_y, ++iter_z) {
+        const double x = *iter_x;
+        const double y = *iter_y;
+        const double z = *iter_z;
+#else
+    pcl::PointCloud<pcl::PointXYZ>::const_iterator point_it = obs.cloud_->begin();
+    for (;point_it < obs.cloud_->end(); ++point_it) {
+        const double x = point_it->x;
+        const double y = point_it->y;
+        const double z = point_it->z;
+#endif
+      // now we need to compute the map coordinates for the observation
+      unsigned int mx, my, mz;
+
+      if (!worldToMap3D(x, y, z, mx, my, mz))
+        continue;
+
+      if (voxel_grid_.markVoxelInMap(mx, my, mz, mark_threshold_))
+      {
+        unsigned int index = getIndex(mx, my);
+
+        costmap_[index] = LETHAL_OBSTACLE;
+        touch(x, y, min_x, min_y, max_x, max_y);
+      }
+    }
+  }
+
+  if (publish_voxel_)
+  {
+    VoxelGrid grid_msg;
+    unsigned int size = voxel_grid_.sizeX() * voxel_grid_.sizeY();
+    grid_msg.size_x = voxel_grid_.sizeX();
+    grid_msg.size_y = voxel_grid_.sizeY();
+    grid_msg.size_z = voxel_grid_.sizeZ();
+    grid_msg.data.resize(size);
+    memcpy(&grid_msg.data[0], voxel_grid_.getData(), size * sizeof(unsigned int));
+
+    grid_msg.origin.x = origin_x_;
+    grid_msg.origin.y = origin_y_;
+    grid_msg.origin.z = origin_z_;
+
+    grid_msg.resolutions.x = resolution_;
+    grid_msg.resolutions.y = resolution_;
+    grid_msg.resolutions.z = z_resolution_;
+    grid_msg.header.frame_id = global_frame_;
+    grid_msg.header.stamp = ros::Time::now();
+    voxel_pub_.publish(grid_msg);
+  }
+
+  updateFootprint(robot_x, robot_y, robot_yaw, min_x, min_y, max_x, max_y);
+}
